#include<bits/stdc++.h>
using namespace std;
const int N=1000010,M=3000010;
int dfn[N],low[N],a[N],dfncnt,id[N],siz[N],scccnt;
bool instk[N];
stack<int> s;
int cnt,head[N],to[M],val[M],nxt[M];
vector<int> mp[N];
map<pair<int,int>,bool> mp1;
int in[N],dp[N];
void add(int u,int v,int w=1)
{
	to[++cnt]=v;
	val[cnt]=w;
	nxt[cnt]=head[u];
	head[u]=cnt;
}
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    s.push(x);
    instk[x]=1;
    for(int i=head[x];i;i=nxt[i])
    {
        int v=to[i];
        if(dfn[v]==0)
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(dfn[x]==low[x])
    {
        scccnt++;
        int top;
        do
        {
            top=s.top();
            instk[top]=0;
            siz[scccnt]++;
            id[top]=scccnt;
            s.pop();
        }while(top!=x);
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        add(u,v);
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int k=head[i];k;k=nxt[k])
        {
            int j=to[k];
            if(id[i]!=id[j]&&!mp1[make_pair(id[i],id[j])])
            {
                mp1[make_pair(id[i],id[j])]=true;
                mp[id[i]].push_back(id[j]);
                in[id[j]]++;
            }
        }
    }
    int flag=1,cnt=0;
    for(int i=1;i<=scccnt;i++)
    {
        if(in[i]==0)
        {
            cnt++;
        }
        if(in[i]!=0||siz[i]>1)
        {
            continue;
        }
        if(flag)
        {
            bool flag1=true;
            for(int j:mp[i])
            {
                if(in[j]<=1)
                {
                    flag1=false;
                    break;
                }
            }
            if(flag1)
            {
                flag=false;
                cnt--;
            }
        }
    }
    printf("%.6lf",1.0*(n-cnt)/n);
    return 0;
}
